from datetime import datetime, timedelta

def build_saml_request(destination_url, user_info):
    # Sanitize user inputs to prevent XML injection
    def sanitize_input(value):
        if value is None:
            return ""
        # Remove or escape problematic XML characters
        return str(value).replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;").replace('"', "&quot;").replace("'", "&apos;")
    
    # Generate unique ID and timestamps
    request_id = f"_{uuid.uuid4().hex}"
    issue_instant = datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ")
    not_on_or_after = (datetime.utcnow() + timedelta(minutes=5)).strftime("%Y-%m-%dT%H:%M:%SZ")
    
    # Sanitize user information
    user_id = sanitize_input(user_info.get('user_id', ''))
    email = sanitize_input(user_info.get('email', ''))
    first_name = sanitize_input(user_info.get('first_name', ''))
    last_name = sanitize_input(user_info.get('last_name', ''))
    
    # Build SAML Request XML
    saml_request = f"""<?xml version="1.0" encoding="UTF-8"?>
<samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
                    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
                    ID="{request_id}"
                    Version="2.0"
                    IssueInstant="{issue_instant}"
                    Destination="{destination_url}"
                    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
                    AssertionConsumerServiceURL="{destination_url}">
    <saml:Issuer>{sanitize_input(user_info.get('issuer', ''))}</saml:Issuer>
    <saml:Subject>
        <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified">{user_id}</saml:NameID>
        <saml:SubjectConfirmation Method="urn:oasis:names:tc:SAML:2.0:cm:bearer">
            <saml:SubjectConfirmationData NotOnOrAfter="{not_on_or_after}"
                                          Recipient="{destination_url}"/>
        </saml:SubjectConfirmation>
    </saml:Subject>
    <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified"
                        AllowCreate="true"/>
</samlp:AuthnRequest>"""
    
    return saml_request

def send_saml_request(destination_url, user_info):
    # Build the SAML request
    saml_request = build_saml_request(destination_url, user_info)
    
    # Encode the SAML request
    encoded_request = base64.b64encode(saml_request.encode('utf-8')).decode('utf-8')
    
    # Prepare form data for POST request
    form_data = {
        'SAMLRequest': encoded_request,
        'RelayState': urllib.parse.quote(user_info.get('relay_state', ''), safe='~()*!.\'')
    }
    
    # Send POST request to Identity Provider
    try:
        response = requests.post(
            destination_url,
            data=form_data,
            headers={'Content-Type': 'application/x-www-form-urlencoded'},
            timeout=30
        )
        return response
    except Exception as e:
        raise Exception(f"Failed to send SAML request: {str(e)}")

